  1	import * as React from 'react';
  2	import {
  3	  Caption,
  4	  InnerScrollContainer,
  5	  IRow,
  6	  ISortBy,
  7	  OnSort,
  8	  SortByDirection,
  9	  Table,
 10	  TableGridBreakpoint,
 11	  Tbody,
 12	  Td,
 13	  Th,
 14	  Thead,
 15	  ThProps,
 16	  Tr
 17	} from '@patternfly/react-table';
 18	import { HistoryManager, URLParam } from '../../app/History';
 19	import { config, RenderResource, Resource, ResourceType } from './Config';
 20	import { VirtualItem } from './VirtualItem';
 21	import { EmptyState, EmptyStateBody, EmptyStateVariant, EmptyStateHeader } from '@patternfly/react-core';
 22	import { KialiAppState } from '../../store/Store';
 23	import { activeNamespacesSelector } from '../../store/Selectors';
 24	import { connect } from 'react-redux';
 25	import { Namespace } from '../../types/Namespace';
 26	import { SortField } from '../../types/SortFilters';
 27	import { NamespaceInfo } from '../../types/NamespaceInfo';
 28	import * as FilterHelper from '../FilterList/FilterHelper';
 29	import * as Sorts from '../../pages/Overview/Sorts';
 30	import { StatefulFiltersRef } from '../Filters/StatefulFilters';
 31	import { kialiStyle } from 'styles/StyleUtils';
 32	import { SortableTh } from 'components/Table/SimpleTable';
 33	import { isKiosk } from 'components/Kiosk/KioskActions';
 34	import { store } from 'store/ConfigStore';
 35	import { classes } from 'typestyle';
 36	
 37	const emptyStyle = kialiStyle({
 38	  borderBottom: 0
 39	});
 40	
 41	// TOP_PADDING constant is used to adjust the height of the main div to allow scrolling in the inner container layer.
 42	const TOP_PADDING = 76 + 160;
 43	
 44	// EMBEDDED_PADDING constant is a magic number used to adjust the height of the main div to allow scrolling in the inner container layer.
 45	// 42px is the height of the first tab menu
 46	const EMBEDDED_PADDING = 42 + 100;
 47	
 48	/**
 49	 * By default, Kiali hides the global scrollbar and fixes the height for some pages to force the scrollbar to appear
 50	 * Hiding global scrollbar is not possible when Kiali is embedded in other application (like Openshift Console)
 51	 * In these cases height is not fixed to avoid multiple scrollbars (https://github.com/kiali/kiali/issues/6601)
 52	 * GLOBAL_SCROLLBAR environment variable is not defined in standalone Kiali application (value is always false)
 53	 */
 54	const globalScrollbar = process.env.GLOBAL_SCROLLBAR ?? 'false';
 55	
 56	// ******************************
 57	// VirtualList and its associated classes are intended to be used for main list pages: Applications,
 58	// Workloads, Services and Istio Config. They share common style and filter integration. They have
 59	// have limitations in scenarios where different personalization is needed (columns style, or layout).
 60	// For a secondary list, rendered inside a detail page, it is recommended the imple be based on a
 61	// Table component, such as in WorkloadServices, WorkloadPods, ServiceInfoWorkload, IstioConfigSubList,
 62	// or TrafficListComponent.
 63	// ******************************
 64	
 65	type Direction = 'asc' | 'desc' | undefined;
 66	
 67	type ReduxProps = { activeNamespaces: Namespace[] };
 68	
 69	type VirtualListProps<R> = ReduxProps & {
 70	  actions?: JSX.Element[];
 71	  children?: React.ReactNode;
 72	  className?: any;
 73	  hiddenColumns?: string[];
 74	  onResize?: (height: number) => void;
 75	  rows: R[];
 76	  sort?: (sortField: SortField<NamespaceInfo>, isAscending: boolean) => void;
 77	  statefulProps?: StatefulFiltersRef;
 78	  type: string;
 79	};
 80	
 81	type VirtualListState<R extends RenderResource> = {
 82	  columns: ResourceType<R>[];
 83	  conf: Resource;
 84	  scrollStyle: string;
 85	  sortBy: {
 86	    direction: Direction;
 87	    index: number;
 88	  };
 89	};
 90	
 91	class VirtualListComponent<R extends RenderResource> extends React.Component<VirtualListProps<R>, VirtualListState<R>> {
 92	  private statefulFilters: StatefulFiltersRef = React.createRef();
 93	
 94	  constructor(props: VirtualListProps<R>) {
 95	    super(props);
 96	    const conf = config[props.type] as Resource;
 97	    const columns = this.getColumns(props.type);
 98	    let index = -1;
 99	    const sortParam = HistoryManager.getParam(URLParam.SORT);
100	
101	    if (sortParam) {
102	      index = conf.columns.findIndex(column => column.param === sortParam);
103	    }
104	
105	    this.state = {
106	      sortBy: {
107	        index,
108	        direction: HistoryManager.getParam(URLParam.DIRECTION) as Direction
109	      },
110	      scrollStyle: kialiStyle({}),
111	      columns,
112	      conf
113	    };
114	  }
115	
116	  onSort = (_event: React.MouseEvent, index: number, direction: SortByDirection): void => {
117	    this.setState({
118	      sortBy: {
119	        index,
120	        direction
121	      }
122	    });
123	
124	    if (direction) {
125	      HistoryManager.setParam(URLParam.DIRECTION, direction);
126	    }
127	
128	    HistoryManager.setParam(URLParam.SORT, String(this.state.columns[index].param));
129	    this.props.sort && this.props.sort(FilterHelper.currentSortField(Sorts.sortFields), direction === 'asc');
130	  };
131	
132	  componentDidMount(): void {
133	    this.updateWindowDimensions();
134	    window.addEventListener('resize', this.updateWindowDimensions);
135	  }
136	
137	  componentWillUnmount(): void {
138	    window.removeEventListener('resize', this.updateWindowDimensions);
139	  }
140	
141	  componentDidUpdate(): void {
142	    const columns = this.getColumns(this.props.type);
143	
144	    if (columns.length !== this.state.columns.length) {
145	      this.setState({ columns: columns });
146	    }
147	  }
148	
149	  getScrollStyle = (height: number): string => {
150	    if (globalScrollbar === 'false') {
151	      return kialiStyle({
152	        height: height,
153	        padding: '1.25rem',
154	        marginBottom: '1.25rem',
155	        width: '100%'
156	      });
157	    }
158	    return kialiStyle({});
159	  };
160	
161	  updateWindowDimensions = (): void => {
162	    const isStandalone = !isKiosk(store.getState().globalState.kiosk);
163	    const topPadding = isStandalone ? TOP_PADDING : EMBEDDED_PADDING;
164	
165	    this.setState(
166	      {
167	        scrollStyle: this.getScrollStyle(window.innerHeight - topPadding)
168	      },
169	      () => {
170	        if (this.props.onResize) {
171	          this.props.onResize(window.innerHeight - topPadding);
172	        }
173	      }
174	    );
175	  };
176	
177	  private getColumns = (type: string): ResourceType<R>[] => {
178	    let columns = [] as ResourceType<R>[];
179	    const conf = config[type] as Resource;
180	
181	    if (conf.columns) {
182	      columns = conf.columns.filter(
183	        info => !this.props.hiddenColumns || !this.props.hiddenColumns.includes(info.title.toLowerCase())
184	      );
185	    }
186	
187	    if (this.props.actions) {
188	      columns.push({
189	        title: '',
190	        name: '',
191	        sortable: false
192	      });
193	    }
194	
195	    return columns;
196	  };
197	
198	  private getSortParams = (
199	    column: SortableTh,
200	    index: number,
201	    sortBy: ISortBy,
202	    onSort: OnSort
203	  ): ThProps['sort'] | undefined => {
204	    return column.sortable
205	      ? {
206	          sortBy: sortBy,
207	          onSort: onSort,
208	          columnIndex: index
209	        }
210	      : undefined;
211	  };
212	
213	  render(): React.ReactNode {
214	    // If there is no global scrollbar, height is fixed to force the scrollbar to appear in the component
215	    const { rows } = this.props;
216	    const { sortBy, columns, conf } = this.state;
217	
218	    const typeDisplay = this.props.type === 'istio' ? 'Istio config' : this.props.type;
219	
220	    const childrenWithProps = React.Children.map(this.props.children, child => {
221	      // Checking isValidElement is the safe way and avoids a TS error too.
222	      if (React.isValidElement(child)) {
223	        return React.cloneElement(child, { ref: this.statefulFilters } as React.Attributes);
224	      }
225	
226	      return child;
227	    });
228	
229	    const rowItems: IRow[] = rows.map((row, index) => {
230	      return (
231	        <VirtualItem
232	          key={`vItem_${index}`}
233	          item={row}
234	          index={index}
235	          columns={this.state.columns}
236	          config={conf}
237	          statefulFilterProps={this.props.statefulProps ? this.props.statefulProps : this.statefulFilters}
238	          action={this.props.actions && this.props.actions[index] ? this.props.actions[index] : undefined}
239	        />
240	      );
241	    });
242	    const table = (
243	      <Table gridBreakPoint={TableGridBreakpoint.none} role="presentation" isStickyHeader>
244	        {conf.caption && <Caption>{conf.caption}</Caption>}
245	        <Thead>
246	          <Tr>
247	            {columns.map((column, index) => (
248	              <Th
249	                key={`column_${index}`}
250	                dataLabel={column.title}
251	                sort={this.getSortParams(column, index, sortBy, this.onSort)}
252	                width={column.width}
253	                textCenter={column.textCenter}
254	              >
255	                {column.title}
256	              </Th>
257	            ))}
258	          </Tr>
259	        </Thead>
260	
261	        <Tbody>
262	          {this.props.rows.length > 0 ? (
263	            rowItems
264	          ) : (
265	            <Tr className={emptyStyle}>
266	              <Td colSpan={columns.length}>
267	                {this.props.activeNamespaces.length > 0 ? (
268	                  <EmptyState variant={EmptyStateVariant.full}>
269	                    <EmptyStateHeader titleText={<>No {typeDisplay} found</>} headingLevel="h5" />
270	                    <EmptyStateBody>
271	                      No {typeDisplay} in namespace
272	                      {this.props.activeNamespaces.length === 1
273	                        ? ` ${this.props.activeNamespaces[0].name}`
274	                        : `s: ${this.props.activeNamespaces.map(ns => ns.name).join(', ')}`}
275	                    </EmptyStateBody>
276	                  </EmptyState>
277	                ) : (
278	                  <EmptyState variant={EmptyStateVariant.full}>
279	                    <EmptyStateHeader titleText="No namespace is selected" headingLevel="h5" />
280	                    <EmptyStateBody>
281	                      There is currently no namespace selected, please select one using the Namespace selector.
282	                    </EmptyStateBody>
283	                  </EmptyState>
284	                )}
285	              </Td>
286	            </Tr>
287	          )}
288	        </Tbody>
289	      </Table>
290	    );
291	    return (
292	      <div className={classes(this.state.scrollStyle, this.props.className)}>
293	        {childrenWithProps}
294	        {this.props.actions ? table : <InnerScrollContainer style={{ maxHeight: '95%' }}>{table}</InnerScrollContainer>}
295	      </div>
296	    );
297	  }
298	}
299	
300	const mapStateToProps = (state: KialiAppState): ReduxProps => ({
301	  activeNamespaces: activeNamespacesSelector(state)
302	});
303	
304	export const VirtualList = connect(mapStateToProps)(VirtualListComponent);

